const path = require('path');
const yaml = require('js-yaml');
const fs = require('fs');

const dataFolder = './data_folder';
const secretsFile = path.join(dataFolder, 'secrets.yaml');
const configFile = path.join(dataFolder, 'work_preferences.yaml');
const resumeFile = path.join(dataFolder, 'plain_text_resume.yaml');

try {
  const secretsContent = fs.readFileSync(secretsFile, 'utf8');
  const configContent = fs.readFileSync(configFile, 'utf8');
  const resumeContent = fs.readFileSync(resumeFile, 'utf8');

  const secrets = yaml.load(secretsContent);
  const config = yaml.load(configContent);
  const resume = yaml.load(resumeContent);

  return {
    llm_api_key: secrets.llm_api_key,
    config: config,
    resume: resume,
    outputFileDirectory: path.join(dataFolder, 'output')
  };
} catch (error) {
  throw new Error(`Configuration loading failed: ${error.message}`);
}

const actions = [
