const fs = require('fs');
const path = require('path');
const base64 = require('js-base64');

const result_base64 = $input.first().json.result_base64;
const suggested_name = $input.first().json.suggested_name;
const outputFileDirectory = $input.first().json.outputFileDirectory;

try {
  const pdfData = Buffer.from(result_base64, 'base64');

  const outputDir = path.join(outputFileDirectory, suggested_name);

  if (!fs.existsSync(outputDir)) {
    fs.mkdirSync(outputDir, { recursive: true });
  }

  const filename = suggested_name.includes('cover') ? 'cover_letter.pdf' : 'resume.pdf';
  const outputPath = path.join(outputDir, filename);

  fs.writeFileSync(outputPath, pdfData);

  return {
    success: true,
    message: `PDF saved to: ${outputPath}`,
    outputPath: outputPath
  };
} catch (error) {
  return {
    success: false,
    error: error.message
  };
}

return {
  status: 'success',
  message: 'Job application documents generated successfully'
};
